data.content:
Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.NotFound);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespectsTimeout()
    {
        // TestContext.CancellationToken fires when [Timeout] expires
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — token that is already cancelled
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var handler = new FakeHandler("data", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_CancelledDuringRequest_ThrowsTaskCanceledException()
    {
        // Arrange — cancel after a short delay to simulate mid-flight cancellation
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        var handler = new DelayHandler(TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test doubles -------------------------------------------------------

    private sealed class FakeHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            });
        }
    }

    private sealed class DelayHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `sealed` test class | Performance + design clarity |
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `_testContext.CancellationToken` with `[Timeout]` | Cooperative timeout — test is cancelled cleanly instead of abandoned |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]`; lets you inspect the exception |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over `HttpClient` behavior |
| Pre-cancelled `CancellationTokenSource` | Tests the "already cancelled" edge case |
| `CancellationTokenSource(TimeSpan)` | Tests mid-flight cancellation without relying on real network delays |

The critical takeaway: **always pass `TestContext.CancellationToken`** to async calls in tests with `[Timeout]`. Without it, the timeout has no way to stop the async operation cooperatively — the test just gets abandoned, potentially leaking resources.
